import{_ as s,o,c as t,a2 as i}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"문서/저널 사이트 VitePress 이관","description":"","frontmatter":{"title":"문서/저널 사이트 VitePress 이관","feature_id":"007","status":"done","created":"2026-06-01 21:55 (KST)","date":"2026-06-01T00:00:00.000Z","tags":["docs","vitepress","migration","publishing"]},"headers":[],"relativePath":"specs/007-vitepress-docs-migration/spec.md","filePath":"specs/007-vitepress-docs-migration/spec.md","lastUpdated":null}'),r={name:"specs/007-vitepress-docs-migration/spec.md"};function a(c,e,l,n,d,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="spec-문서-저널-사이트-vitepress-이관" tabindex="-1">Spec: 문서/저널 사이트 VitePress 이관 <a class="header-anchor" href="#spec-문서-저널-사이트-vitepress-이관" aria-label="Permalink to &quot;Spec: 문서/저널 사이트 VitePress 이관&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>지금 <code>blog/</code> 의 문서·저널 사이트는 Docusaurus(React/MDX) 로 만들어져 있다. 이 사이트는 두 가지를 게시한다 — (1) <code>specs/</code> 에서 동기화해 온 기능 명세 문서, (2) 만드는 과정을 기록한 저널 글(현재 12편). <code>main</code> 에 푸시하면 GitHub Actions 가 specs 를 동기화하고 빌드해 GitHub Pages 로 배포한다.</p><p>운영자는 이 사이트를 참조 프로젝트 (<code>../youtube-do-not-build-agents-main</code>, VitePress 기반)와 <strong>동일한 형태</strong> — 같은 디렉터리/네비게이션 구조, 같은 톤의 홈(hero) 화면, 한국어 로컬 검색, &quot;최근 먼저&quot; 정렬 — 로 통일하고 싶어 한다. MDX·React 의존으로 생기는 빌드 취약성(예: spec 동기화 시 MDX 파싱이 깨지는 사고)을 줄이고, 더 가벼운 마크다운 중심 문서 도구로 옮기는 것이 목적이다.</p><p>이 기능은 <strong>문서/저널 게시 사이트</strong>(<code>blog/</code>)만 대상으로 한다. 관리자 콘솔 SPA(spec 006 / <code>app/</code>)는 대상이 <strong>아니다</strong>.</p><h2 id="clarifications" tabindex="-1">Clarifications <a class="header-anchor" href="#clarifications" aria-label="Permalink to &quot;Clarifications&quot;">​</a></h2><h3 id="session-2026-06-01" tabindex="-1">Session 2026-06-01 <a class="header-anchor" href="#session-2026-06-01" aria-label="Permalink to &quot;Session 2026-06-01&quot;">​</a></h3><ul><li>Q: VitePress 는 내장 블로그가 없는데, 저널 글 12편을 &quot;최근 먼저&quot;로 자동 정렬된 목록으로 보여주는 방식은? → A: 빌드 시 자동 생성 인덱스(data loader/ 스크립트로 저널 디렉터리를 스캔해 created/date 내림차순 목록 생성, 새 글 추가 시 수작업 없이 반영).</li><li>Q: VitePress 사이드바는 기본 수동인데, <code>specs/</code> 에 새 폴더를 추가하면 수작업 없이 네비에 반영(FR-6)되게 하려면? → A: specs 동기화 단계에서 사이드바 설정을 자동 생성(feature 번호 큰 것 먼저).</li><li>Q: 내부 링크가 깨졌을 때 사이트 빌드 정책은? → A: 빌드 실패(strict) — 깨진 내부 링크가 있으면 빌드를 실패시켜 CI 게이트로 작동.</li><li>Q: 배포 공개 base 경로는? → A: <code>/blog/</code> 유지(리포 이름이 <code>blog</code> 이라 GitHub Pages 경로와 일치).</li><li>Q: 참조 프로젝트의 <code>.vitepress/theme/</code>(index.ts + 280줄 custom.css, 갈색· Noto Serif KR 세리프 &quot;퍼블리케이션&quot; 디자인)를 어느 수준까지 그대로 쓰는가? → A: <strong>theme/ 전체를 그대로</strong> 가져와 적용한다(index.ts·custom.css verbatim). 사이트명 등 텍스트만 교체하고, 별도 색/폰트 재작성(claude.ai 톤 이식)은 하지 않는다.</li></ul><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><ul><li><p><strong>포함</strong>:</p><ul><li><code>blog/</code> 의 Docusaurus 사이트를 VitePress 사이트로 교체한다. 참조 프로젝트와 동일한 형태(홈 hero + features, 좌측 사이드바 네비, 상단 nav, 로컬 검색, 이전/다음·최종수정일·푸터)를 따른다.</li><li>기존 콘텐츠를 <strong>전부 이관</strong>한다. <ul><li>저널 글 12편(현재 <code>blog/blog/*.md</code>) → VitePress 의 저널/작업로그 섹션. frontmatter 의 <code>created</code>(시간 포함)·<code>date</code> 규칙과 &quot;최근 먼저&quot; 정렬을 유지한다.</li><li><code>specs/</code> → 사이트의 명세 섹션. 기존 동기화 산출물(spec/plan/ tasks/research 등)을 VitePress 가 읽을 수 있는 형태로 게시한다.</li></ul></li><li><strong>게시 파이프라인 유지</strong>: <code>main</code> 푸시 시 specs 동기화 → 사이트 빌드 → GitHub Pages 배포가 계속 동작한다. 빌드 단계만 Docusaurus → VitePress 로 교체한다. 동기화 스크립트는 VitePress 디렉터리 규칙에 맞게 조정한다.</li><li>한국어 UI 문자열·로컬 검색·KST/&quot;최근 먼저&quot; 규칙 등 현재 사이트가 주던 독자 경험을 보존한다.</li><li>GitHub Pages 의 공개 경로(base URL)와 사이트 진입점이 깨지지 않게 한다.</li></ul></li><li><p><strong>제외(Non-goals)</strong>:</p><ul><li>관리자 콘솔 SPA(spec 006), <code>app/</code>(백엔드), <code>vendor/vugrid/</code> 자체의 기능 변경.</li><li>저널/명세 <strong>내용</strong>의 재작성(이관에 필요한 형식 조정 외 본문 수정 없음).</li><li>새 콘텐츠 작성, 디자인 전면 재설계(참조 프로젝트 형태를 따르는 수준 이상의 독자적 테마 작업).</li><li>도메인/호스팅 변경(현재 GitHub Pages 유지).</li></ul></li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li><strong>독자 — 사이트 탐색</strong>: 방문자로서, 홈(hero)에서 개요·저널·명세로 바로 갈 수 있고 좌측 사이드바로 문서 사이를 오갈 수 있어, 발표 참조 사이트와 같은 친숙한 방식으로 내용을 읽고 싶다.</li><li><strong>독자 — 검색</strong>: 방문자로서, 한국어로 사이트 내 검색을 해서 원하는 명세·저널 항목을 빠르게 찾고 싶다.</li><li><strong>독자 — 저널 최신글</strong>: 방문자로서, 저널 목록에서 가장 최근 글이 맨 위에 오기를 기대한다(현재 규칙 유지).</li><li><strong>운영자 — 게시</strong>: 메인테이너로서, <code>main</code> 에 푸시하면 명세가 자동 동기화되고 사이트가 빌드·배포되어, 별도 수작업 없이 최신 문서가 공개되기를 원한다.</li><li><strong>운영자 — 명세 추가</strong>: 메인테이너로서, <code>specs/</code> 에 새 기능 폴더를 추가하면 사이트의 명세 섹션과 네비게이션에 자동으로 반영되기를 원한다.</li><li><strong>운영자 — 로컬 미리보기</strong>: 기여자로서, 로컬에서 사이트를 실행/빌드해 푸시 전에 깨진 링크·파싱 오류 없이 렌더링되는지 확인하고 싶다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>FR-1</strong>: <code>blog/</code> 사이트는 VitePress 로 빌드되며, Docusaurus(React/MDX) 런타임 의존을 제거한다.</li><li><strong>FR-2</strong>: 사이트 구조·네비게이션은 참조 프로젝트와 동일한 형태를 따른다 — 홈(hero + features), 상단 nav, 좌측 사이드바(섹션별 그룹), 이전/다음 · 최종 수정일 · 푸터 · 목차(outline). <strong>시각 테마는 참조의 <code>.vitepress/theme/</code> (<code>index.ts</code> + <code>custom.css</code>)를 그대로 채택</strong>한다(갈색·Noto Serif KR 세리프 퍼블리케이션 디자인). 사이트명 등 텍스트만 교체하며 별도 테마 재작성은 없다.</li><li><strong>FR-3</strong>: 최소한 다음 섹션을 갖춘다 — (a) 개요/홈, (b) 저널(개발 로그), (c) 명세(specs). 명세와 저널이 상단 nav·사이드바에서 모두 접근 가능해야 한다.</li><li><strong>FR-4</strong>: 기존 저널 글 12편이 모두 새 사이트에서 접근 가능하며, 각 글의 제목·작성 시각(<code>created</code>, 시간 포함)·태그가 보존된다.</li><li><strong>FR-5</strong>: 저널 목록은 <strong>빌드 시 자동 생성되는 인덱스</strong>로 제공된다 — 저널 디렉터리를 스캔해 <code>created</code>/<code>date</code> <strong>내림차순(&quot;최근 먼저&quot;)</strong> 으로 나열하며, 새 글을 추가하면 수작업 편집 없이 목록 최상단에 반영된다. 그 외 모든 시간순 목록도 내림차순으로 정렬한다. 명세 목록은 feature 번호가 큰 것이 먼저 온다.</li><li><strong>FR-6</strong>: <code>specs/</code> 의 명세 문서가 사이트에 게시되며, <strong>specs 동기화 단계가 사이드바 네비게이션 설정을 자동 생성</strong>한다(feature 번호가 큰 것 먼저). 새 spec 폴더를 추가하면 수작업 네비 편집 없이 사이트에 반영된다.</li><li><strong>FR-7</strong>: 사이트는 한국어(ko-KR) 로컬 검색을 제공하며, UI 문자열(검색· 이전/다음·최종 수정일 등)이 한국어로 표시된다.</li><li><strong>FR-8</strong>: GitHub Actions 워크플로가 <code>main</code> 푸시 시 specs 동기화 → VitePress 빌드 → GitHub Pages 배포를 수행한다. 트리거 경로(specs/<strong>, blog/</strong>, 동기화 스크립트, 워크플로 파일)는 새 구조에 맞게 갱신된다.</li><li><strong>FR-9</strong>: 배포된 사이트의 공개 base 경로는 <strong><code>/blog/</code></strong> 로 유지하며(리포 이름 <code>blog</code> 과 GitHub Pages 경로 일치), 내부 링크·자산이 404 없이 로드된다.</li><li><strong>FR-10</strong>: 사이트 빌드는 <strong>깨진 내부 링크가 있으면 실패(strict)</strong> 한다 — CI 게이트로 작동해 깨진 링크가 있는 사이트가 배포되지 않게 한다. 또한 MDX 특유의 파싱 취약성으로 인한 사고가 재발하지 않도록 일반 마크다운으로 동작한다.</li><li><strong>FR-11</strong>: 로컬에서 개발 서버 실행과 정적 빌드가 모두 가능하다.</li><li><strong>FR-12</strong>: 이관 후 더 이상 쓰이지 않는 Docusaurus 전용 자산(config· sidebars·React 페이지/컴포넌트 등)은 사이트가 동작하지 않게 남겨두지 않고 정리한다.</li><li><strong>FR-13</strong>: mermaid 다이어그램은 새 사이트에서 동등하게 렌더링된다. vugrid 데모 iframe 등 Docusaurus 특유의 특수 임베드는 동등 재현 대상이 아니며, 링크/이미지 등 VitePress 에서 안정적으로 동작하는 형태로 유지·단순화한다.</li></ul><h2 id="success-criteria" tabindex="-1">Success Criteria <a class="header-anchor" href="#success-criteria" aria-label="Permalink to &quot;Success Criteria&quot;">​</a></h2><ul><li><strong>SC-1</strong>: <code>main</code> 에 푸시하면 사람의 추가 개입 없이 사이트가 빌드·배포되고, 공개 URL 에서 홈·저널·명세 섹션이 정상 로드된다.</li><li><strong>SC-2</strong>: 이관 전 존재하던 저널 글 12편이 100% 새 사이트에서 열람 가능하며, 저널 목록 최상단은 가장 최근 글이다.</li><li><strong>SC-3</strong>: <code>specs/</code> 의 모든 기능 명세가 사이트에서 열람 가능하고, 새 spec 폴더를 추가한 뒤 게시했을 때 수작업 네비 편집 없이 목록에 나타난다.</li><li><strong>SC-4</strong>: 한국어 검색어로 명세·저널 항목을 검색해 결과로 이동할 수 있다.</li><li><strong>SC-5</strong>: 독자가 홈 → 개요/저널/명세 → 개별 문서로 3클릭 이내에 도달하고, 이전/다음·사이드바로 인접 문서를 오갈 수 있다.</li><li><strong>SC-6</strong>: 로컬 빌드가 오류 없이 완료되고, 깨진 내부 링크가 0건이다.</li><li><strong>SC-7</strong>: 빌드 산출물·의존성에 Docusaurus/React 런타임이 포함되지 않는다.</li></ul><h2 id="assumptions" tabindex="-1">Assumptions <a class="header-anchor" href="#assumptions" aria-label="Permalink to &quot;Assumptions&quot;">​</a></h2><ul><li>참조 프로젝트(<code>../youtube-do-not-build-agents-main</code>)의 VitePress 구성 (config·테마·홈·섹션 패턴)을 형태의 기준으로 삼는다. 콘텐츠 분류(개요/ 전문/주제별/작업로그)는 이 저장소의 실제 콘텐츠(개요/저널/명세)에 맞춰 대응시킨다.</li><li>호스팅은 GitHub Pages 를 유지하며, 공개 base 경로는 <strong><code>/blog/</code></strong> 로 확정한다 (Clarifications 참조).</li><li>저널 글은 frontmatter 의 <code>created</code>(시간 포함)·<code>date</code> 규칙을 그대로 유지 하며, VitePress 에서도 이 값으로 정렬·표기한다.</li><li>specs 동기화는 현재처럼 빌드 시점에 <code>specs/</code> → 사이트 콘텐츠 디렉터리로 복사/변환하는 방식을 유지한다(저장소에 중복 사본을 영구 보관하지 않음).</li><li>콘텐츠 본문은 일반 Markdown 으로 충분히 렌더링되며, MDX/React 컴포넌트에 의존하던 부분은 VitePress 가 지원하는 방식(Markdown/Vue, mermaid 등)으로 대체 가능하다.</li><li>저널 글의 공개 URL 은 Docusaurus 블로그 라우팅(<code>/journal/&lt;slug&gt;</code>)에서 VitePress 파일경로 라우팅(<code>/journal/&lt;파일명&gt;</code>)으로 바뀐다. 기존 인바운드/SEO 링크 보존(리디렉션)은 본 기능 범위가 아니다(현 외부 유입 미미, Non-goal).</li></ul><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>게시 파이프라인: GitHub Actions(<code>publish-blog.yml</code>)와 specs 동기화 스크립트(<code>scripts/sync-specs-to-blog.sh</code>)에 의존하며, 이관 시 함께 갱신한다.</li><li>GitHub Pages 설정(공개 URL·base 경로).</li><li>저널/명세 frontmatter 규칙(<code>created</code>/<code>date</code>, &quot;최근 먼저&quot;) — CLAUDE.md 의 문서 작성 규칙을 따른다.</li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>(해결됨) 리치 콘텐츠 재현 수준: <strong>mermaid 다이어그램은 VitePress 에서 동등하게 재현</strong>하고, vugrid 데모 iframe 등 그 외 특수 임베드는 현재 형태를 무리하게 재현하지 않고 링크/이미지 등으로 유지·단순화한다. (FR-13 참조)</li></ul>',22)])])}const h=s(r,[["render",a]]);export{p as __pageData,h as default};
